#include <bits/stdc++.h>
using namespace std;
int main(){
    int n; cin >> n;
    vector<int> bloomDay(n);
    for(int i = 0; i < n; i++) cin >> bloomDay[i];
    int m, k; cin >> m >> k;

    auto possible = [&](int days){
        int bouquets = 0;
        int flowers = 0;
        for(int day : bloomDay){
            if (day <= days) {
                flowers++;
            } else {
                flowers = 0;
            }
            if (flowers == k) {
                bouquets++;
                flowers = 0;
            }
        }
        return bouquets >= m;
    };

    int low = *min_element(bloomDay.begin(), bloomDay.end());
    int high = *max_element(bloomDay.begin(), bloomDay.end());
    while (low < high) {
        int mid = low + (high - low) / 2;
        if (possible(mid)) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    cout << low;
}
